/**
 * Wire-nav step — wires `primaryCountry` + `coApplicableCountries`
 * nav refs (skipped for Etc/* pseudo-zones lacking a primary).
 */
export function wireTimezoneNav(): void {
  for (const tz of TimezoneLookup.all) {
    const mut = tz as { -readonly [K in keyof Timezone]: Timezone[K] };
    if (tz.primaryCountryIso31661Alpha2Code !== undefined) {
      const primary = CountryLookup.byCode[tz.primaryCountryIso31661Alpha2Code];
      if (primary !== undefined) mut.primaryCountry = primary;
    }
    if (tz.coApplicableCountryIso31661Alpha2Codes.size > 0) {
      const list: Country[] = [];
      for (const cc of tz.coApplicableCountryIso31661Alpha2Codes) {
        const country = CountryLookup.byCode[cc];
        if (country !== undefined) list.push(country);
      }
      mut.coApplicableCountries = list;
    }
  }
}